  ('fire-eq-eng-moex-00384', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法規定，對於消防設備師或消防設備士之相關規定，下列何者錯誤？', '["高層建築物或地下建築物消防安全設備之定期檢修，應委託消防設備師為之", "消防設備士可進行消防安全設備之裝置及檢修", "消防設備師可進行消防安全設備之裝置及檢修", "消防設備師或消防設備士未達定量人數前，得由現有相關專門職業及技術人員或技術士暫 行為之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00385', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法規定，管理權人對其實際支配管理之場所，應設置並維護其消防安全設備。以國內 私立大學而言，其管理權人為何人？', '["校長", "總務長", "董事長", "學務長"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00386', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '有關消防設備師及消防設備士之講習與積分相關規定，下列何者正確？', '["中央主管機關舉辦或認可之講習會、研討會或專題演講之每項課程或講題，其總分以40分 為限", "消防設備師及消防設備士，自取得證書日起每 3 年應接受講習一次或取得累計積分達 180 分以上之訓練證明文件", "中央主管機關舉辦或認可之專業訓練課程，每小時積分20分", "研究所以上之在職進修或推廣教育，取得學分或結業證明者，每一學分積分20分，單一課 程以40分為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00387', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法施行細則，有關消防防護計畫須包括事項，下列何者錯誤？', '["應對於消防安全設備進行維護管理", "具有防止縱火措施", "滅火、通報及避難訓練之實施；每半年至少應舉辦一次，每次不得少於4小時，並應事先 通報當地消防機關", "遇有增建、改建、修建、室內裝修施工時，應依原訂消防防護計畫，監督施工單位用火、 用電情形"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00388', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依住宅用火災警報器設置辦法，下列敘述何者正確？', '["寢室、樓梯及走廊等空間，應設置定溫式", "裝設位置應距離出風口1.8公尺以上", "裝置於牆面者，距天花板或樓板下方15公分以上50公分以下", "裝置於居室牆面為原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00389', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '下列有關消防法第2條管理權人之說明，何者錯誤？', '["消防安全設備之設置維護費用，最終是否係由消防法所定之「管理權人」負擔，並非消防 法規範之範疇，當事人得透過契約自行約定經費最終之負擔對象及方式", "連棟式建築物之所有人將建築物出租而供他人使用時，必須在契約載明消防安全事項之權 利義務轉移者，始以使用人為管理權人", "私立學校或公立學校之場所均應以學校校長為管理權人", "若場所之營業地點、營業項目、統一編號及違規事實等並無不同，僅管理權人變更時，則 消防機關逕對變更後之管理權人依法接續查處作為，抑或對變更後之管理權人重為查處程 序，均無不可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00390', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法第 73 條之 1 規定，下列敘述何者錯誤？', '["串接使用量在超過300公斤至1,000公斤以下者，應設置自動緊急遮斷裝置", "串接使用量在超過120公斤至300公斤以下者，容器應與用火設備保持2公尺以上距離", "串接使用量在80公斤以上至120公斤以下者，應設置標示板標示緊急聯絡人姓名及電話", "液化石油氣販賣場所之經營者發現供氣之容器串接使用場所無嚴禁煙火標示者，不得供氣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00391', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體製造儲存處理場所設置標準暨安全管理辦法第 73 條之 2 規定，下列敘述何者正確？', '["為避免液化石油氣容器放置室內，漏氣時易於蓄積而致災，爰明定新建及既存建築物之液 化石油氣容器均應設置於室外或屋外", "本條於110年11月10日修正發布，惟為減緩實務衝擊，爰另定本條自111年7月1日施 行", "如設置於屋外確有困難，且設置防止氣體滯留之有效通風裝置者，則不受本條容器應設置 於室外或屋外之限制", "液化石油氣之使用量在20公斤以下者，容器得不受應設置於室外或屋外之限制"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-00392', 'fire-eq-eng', 'fire-eq-eng-moex-111-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依據各類場所消防安全設備設置標準第 30 條之 1 規定，下列場所何者無須設置防災監控系 統綜合操作裝置？', '["高層建築物", "總樓地板面積在50,000平方公尺以上之建築物", "總樓地板面積在3,000平方公尺以上之地下建築物", "總樓地板面積在1,000平方公尺以上之複合用途建築物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:15+00:00", "source_pdf_sha1": "3e004211f84c", "answer_pdf_sha1": "8a19caca295e", "source_family": "moex-gov-tw", "moex": {"exam_code": "111060", "c": "401", "s": "0802", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "111", "exam_name": "111年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
